create table email_subscriptions(id uuid primary key default gen_random_uuid(),email_normalized text not null unique,email_hash text not null,status text not null check(status in('pending','active','unsubscribed','bounced','complained')),probability_threshold integer check(probability_threshold in(60,70,80) or probability_threshold is null),notify_threshold_crossing boolean default true,notify_confirmed_reset boolean default true,notify_forecast_reversal boolean default false,confirmation_token_hash text,confirmation_expires_at timestamptz,unsubscribe_token_hash text not null,confirmed_at timestamptz,unsubscribed_at timestamptz,last_threshold_state text check(last_threshold_state in('below','above','rearmed') or last_threshold_state is null),created_at timestamptz default now(),updated_at timestamptz default now());
create table notification_events(id uuid primary key default gen_random_uuid(),event_key text unique not null,notification_type text not null,forecast_id uuid references forecasts,reset_event_id uuid references known_reset_events,probability integer,metadata jsonb default '{}',created_at timestamptz default now());
create table email_deliveries(id uuid primary key default gen_random_uuid(),email_subscription_id uuid not null references email_subscriptions,notification_event_id uuid references notification_events,email_type text not null,provider text not null,provider_message_id text,status text not null,idempotency_key text unique not null,attempted_at timestamptz default now(),delivered_at timestamptz,error_message text,metadata jsonb default '{}');
alter table email_subscriptions enable row level security;alter table notification_events enable row level security;alter table email_deliveries enable row level security;
-- No public policies: service-role server code is the only reader/writer.
create index on email_subscriptions(status,probability_threshold);create index on email_deliveries(provider_message_id);
